example.code:
TIERS = {
    "kubectl_get":      Tier.T0,   # read
    "kubectl_logs":     Tier.T0,
    "kubectl_restart":  Tier.T1,   # safe-ish mutation
    "scale_replica":    Tier.T1,
    "kubectl_delete":   Tier.T2,   # destructive
    "db_drop_table":    Tier.T2,
}
def call(name, args, approval=None):
    tier = TIERS.get(name, Tier.T2)              # unknown -> T2
    if tier is Tier.T2 and not verify(approval, name, args):
        raise PermissionError(f"{name} requires human approval")
    audit.append(name, args, tier, approval)
    return _dispatch(name, args)

# Anti: tier comes from the LLM-supplied argument
def call(name, args):
    if args.get("tier") == "destructive" and not args.get("approved"):
        raise PermissionError(...)
    return _dispatch(name, args)
